<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('finance');$q=trim((string)query('search'));if($q!==''){$students=db_all('SELECT s.id,s.student_number,u.name,u.email,COALESCE(fc.status,"pending") status,fc.remarks,fc.cleared_at FROM students s JOIN users u ON u.id=s.user_id LEFT JOIN finance_clearance fc ON fc.student_id=s.id WHERE u.name LIKE :n OR s.student_number LIKE :num ORDER BY u.name',['n'=>"%$q%",'num'=>"%$q%"]);}else{$students=db_all('SELECT s.id,s.student_number,u.name,u.email,COALESCE(fc.status,"pending") status,fc.remarks,fc.cleared_at FROM students s JOIN users u ON u.id=s.user_id LEFT JOIN finance_clearance fc ON fc.student_id=s.id ORDER BY u.name');}$page_title='Finance Students - SMIS';include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Student Payment Status</h1><p>Search students and review financial clearance records.</p></div><div class="card"><div class="card-body"><form method="get" class="hero-actions"><input class="form-control" name="search" value="<?=e($q)?>" placeholder="Search name or student number"><button class="btn btn-secondary">Search</button></form></div></div><div class="card"><div class="card-body"><table class="table"><thead><tr><th>Student</th><th>Email</th><th>Payment status</th><th>Remarks</th><th>Updated</th><th></th></tr></thead><tbody><?php foreach($students as $s):?><tr><td><strong><?=e($s['name'])?></strong><br><small><?=e($s['student_number'])?></small></td><td><?=e($s['email'])?></td><td><?=status_badge($s['status'])?></td><td><?=e($s['remarks']??'-')?></td><td><?=format_datetime($s['cleared_at'])?></td><td><a class="action-btn action-edit" href="<?=url('finance/clearances.php?action=edit&id='.$s['id'])?>">Manage</a></td></tr><?php endforeach?></tbody></table></div></div><?php include __DIR__.'/../includes/footer.php';?>
